import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext'; // Using your shared context
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { Cpu, Terminal, Lock, ShieldCheck } from 'lucide-react';
import toast from 'react-hot-toast';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const { theme } = useTheme(); // Consuming your theme.js tokens
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('FIELDS_REQUIRED');
    
    const toastId = toast.loading('INITIALIZING_SECURE_HANDSHAKE...');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: toastId });
      navigate('/dashboard'); 
    } catch (err) { 
      toast.error('GATE_REJECTION: INVALID_CREDENTIALS', { id: toastId }); 
    } finally { 
      setLoading(false); 
    }
  };

  const styles = {
    // 🎯 Fix: flex-center ensures the card is in the middle of the screen
    container: { 
      minHeight: '85vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      padding: '2rem' 
    },
    // 💎 Terminal Card Logic: Small, compact, and centered
    card: { 
      width: '100%', 
      maxWidth: '420px', 
      padding: '3rem', 
      backgroundColor: 'var(--card-bg)', 
      borderRadius: '24px', 
      border: '1px solid var(--border-color)', 
      boxShadow: 'var(--shadow-soft)',
      position: 'relative',
      overflow: 'hidden'
    },
    headerIcon: {
      display: 'flex',
      justifyContent: 'center',
      marginBottom: '1.5rem',
      color: 'var(--primary-accent)'
    },
    title: { 
      fontSize: '2rem', 
      color: 'var(--text-main)', 
      marginBottom: '0.5rem', 
      textAlign: 'center',
      textTransform: 'uppercase',
      letterSpacing: '0.3em',
      fontWeight: '300'
    },
    subtitle: {
      textAlign: 'center',
      fontSize: '10px',
      color: 'var(--text-muted)',
      textTransform: 'uppercase',
      letterSpacing: '0.25em',
      marginBottom: '2.5rem'
    },
    inputGroup: { position: 'relative', marginBottom: '1.5rem', width: '100%' },
    label: {
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      fontSize: '10px',
      color: 'var(--primary-accent)',
      fontWeight: 'bold',
      textTransform: 'uppercase',
      letterSpacing: '0.1em',
      marginBottom: '8px',
      marginLeft: '4px'
    },
    // ⚡ Cyber Input Logic: Uses your theme.js variables
    input: { 
      width: '100%', 
      padding: '1rem 3.5rem 1rem 1rem', 
      backgroundColor: 'var(--input-bg)', 
      border: '1px solid var(--border-color)', 
      borderRadius: '12px', 
      color: 'var(--text-main)', 
      fontSize: '14px', 
      outline: 'none',
      transition: 'all 0.3s ease',
      boxSizing: 'border-box'
    },
    toggleBtn: { 
      position: 'absolute', 
      right: '15px', 
      bottom: '12px', 
      background: 'none', 
      border: 'none', 
      color: 'var(--text-muted)', 
      cursor: 'pointer', 
      fontSize: '1.1rem'
    },
    // 🚀 Emerald Button: High-contrast action
    button: { 
      width: '100%', 
      padding: '1rem', 
      marginTop: '1rem', 
      backgroundColor: 'var(--primary-accent)', 
      color: '#000', 
      border: 'none', 
      borderRadius: '12px', 
      fontWeight: 'bold',
      textTransform: 'uppercase',
      letterSpacing: '0.2em',
      fontSize: '12px',
      cursor: 'pointer', 
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '10px',
      transition: 'all 0.3s ease'
    },
  };

  return (
    <div style={styles.container} className="reveal-data">
      <div style={styles.card}>
        {/* Laser Scan Decor */}
        <div className="absolute top-0 left-0 w-full h-[1px] bg-emerald-500/40 shadow-[0_0_15px_var(--accent-glow)] animate-scan" />
        
        <div style={styles.headerIcon}>
          <Cpu size={42} className="animate-pulse" />
        </div>

        <h2 style={styles.title}>Access_Gate</h2>
        <p style={styles.subtitle}>Node_ID: 8000 // Security_Protocol</p>

        <form onSubmit={handleLogin}>
          <div style={styles.inputGroup}>
            <label style={styles.label}><Terminal size={12} /> Operator_Email</label>
            <input 
              type="email" 
              placeholder="operator@finify.ai" 
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
              style={styles.input} 
              className="focus:border-emerald-500"
            />
          </div>
          
          <div style={styles.inputGroup}>
            <label style={styles.label}><Lock size={12} /> Secure_Key</label>
            <input 
              type={showPass ? "text" : "password"} 
              placeholder="••••••••" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              style={styles.input} 
              className="focus:border-emerald-500"
            />
            <button type="button" onClick={() => setShowPass(!showPass)} style={styles.toggleBtn}>
              {showPass ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>
          
          <button type="submit" style={styles.button} disabled={loading} className="hover:scale-[1.02]">
            {loading ? 'SYNCHRONIZING...' : <><ShieldCheck size={16}/> Connect_to_Terminal</>}
          </button>
        </form>

        <div style={{textAlign: 'center', marginTop: '2rem', paddingTop: '1.5rem', borderTop: '1px solid rgba(255,255,255,0.05)'}}>
            <Link to="/register" style={{color: 'var(--primary-accent)', fontSize: '10px', textTransform: 'uppercase', letterSpacing: '0.1em'}}>
              Initialize_New_Identity
            </Link>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
